import {FixedPointMathLib} from "solady/src/utils/FixedPointMathLib.sol";

abstract contract BaseAuction is PriceManager, ITypeAndVersion, Caller, IBaseAuction {
  using EnumerableSet for EnumerableSet.AddressSet;
